import{_ as e,o,c as n,ag as a}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"Working offline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/offline.md","filePath":"guide/offline.md","lastUpdated":1776620726000}'),r={name:"guide/offline.md"};function i(s,t,l,d,h,c){return o(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="working-offline" tabindex="-1">Working offline <a class="header-anchor" href="#working-offline" aria-label="Permalink to &quot;Working offline&quot;">​</a></h1><p>This is the most important thing to understand about Fateh HR. <strong>Everything important works offline.</strong></p><p>If you&#39;re in a warehouse with no signal, on a delivery route, in an underground carpark, or just on a flight — keep using the app exactly as normal. Nothing is lost.</p><h2 id="what-works-offline" tabindex="-1">What works offline <a class="header-anchor" href="#what-works-offline" aria-label="Permalink to &quot;What works offline&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Offline?</th><th>Notes</th></tr></thead><tbody><tr><td>Check-in / Check-out</td><td>✅</td><td>GPS + selfie captured locally, stored until network returns</td></tr><tr><td>Apply for leave</td><td>✅</td><td>Form submit queues; shows as &quot;Pending sync&quot; in your leave list</td></tr><tr><td>File expense claim</td><td>✅</td><td>Receipt photo kept on device, syncs with the claim</td></tr><tr><td>View attendance calendar</td><td>✅</td><td>Shows last-fetched data; new days appear when you&#39;re back online</td></tr><tr><td>View payslips list</td><td>✅</td><td>Shows last-fetched list</td></tr><tr><td>View a payslip&#39;s details</td><td>⚠️</td><td>Only if you viewed it at least once while online</td></tr><tr><td>Download payslip PDF</td><td>⚠️</td><td>Cached copy if you downloaded it online before</td></tr><tr><td>View check-in history</td><td>✅</td><td>Your queued offline check-ins show up tagged <strong>&quot;Pending sync&quot;</strong></td></tr><tr><td>Change profile</td><td>✅</td><td>Queues the update</td></tr><tr><td>Log in for the first time</td><td>❌</td><td>Requires initial network to get your API token</td></tr><tr><td>View announcements</td><td>⚠️</td><td>Only cached ones</td></tr></tbody></table><h2 id="the-sync-bar" tabindex="-1">The sync bar <a class="header-anchor" href="#the-sync-bar" aria-label="Permalink to &quot;The sync bar&quot;">​</a></h2><p>At the top of every screen (below the title) you&#39;ll see a thin status bar. Watch it.</p><table tabindex="0"><thead><tr><th>State</th><th>What it means</th><th>What to do</th></tr></thead><tbody><tr><td><strong>Synced now</strong></td><td>Everything saved to server</td><td>Nothing</td></tr><tr><td><strong>Synced 3 min ago</strong></td><td>All caught up, last sync was 3 min ago</td><td>Nothing</td></tr><tr><td><strong>5 changes pending · tap to sync</strong></td><td>You did things offline; they&#39;re waiting</td><td>Tap if you want to force sync (it&#39;ll happen automatically when online anyway)</td></tr><tr><td><strong>Syncing…</strong></td><td>Actively uploading right now</td><td>Wait a few seconds</td></tr><tr><td><strong>Offline — working locally</strong></td><td>No network detected</td><td>Keep using the app normally</td></tr><tr><td><strong>2 sync errors</strong></td><td>Something failed upload</td><td>Tap it, then Retry</td></tr></tbody></table><h2 id="how-offline-check-ins-work" tabindex="-1">How offline check-ins work <a class="header-anchor" href="#how-offline-check-ins-work" aria-label="Permalink to &quot;How offline check-ins work&quot;">​</a></h2><p>When you tap Check In without network:</p><ol><li>The app captures your GPS coords, address (if it was cached), task, and selfie</li><li>It <strong>timestamps the action right now</strong> — not when it syncs later</li><li>Everything is stored in the app&#39;s local database</li><li>You see <strong>&quot;Queued — will sync when online.&quot;</strong></li><li>The item appears in your Check-in history tagged <strong>&quot;Pending sync&quot;</strong></li></ol><p>When you get back online:</p><ol><li>The sync bar flips to <strong>Syncing…</strong></li><li>Each queued item uploads one at a time, in the order you did them</li><li>Selfie photos upload first, then the check-in is created with the uploaded photo&#39;s URL</li><li>Sync bar goes to <strong>Synced now</strong></li><li>The <strong>&quot;Pending sync&quot;</strong> tags disappear from your history</li></ol><p><strong>The timestamp you see in the server / ERP is your ORIGINAL capture time — not the sync time.</strong> So if you checked in at 08:00 and only got signal at 14:00, the record correctly says 08:00.</p><h2 id="how-offline-leave-expense-works" tabindex="-1">How offline leave / expense works <a class="header-anchor" href="#how-offline-leave-expense-works" aria-label="Permalink to &quot;How offline leave / expense works&quot;">​</a></h2><p>Same pattern. The form submit goes straight into the queue instead of failing. Your leave list shows the request tagged <strong>&quot;Pending Sync&quot;</strong> until it reaches the server.</p><p><strong>Important:</strong> if your leave or expense submission has a <strong>validation error</strong> (e.g. you don&#39;t have enough leave balance), the app catches that and shows the error <strong>immediately</strong> instead of queueing a submission that would never succeed. This only happens when you&#39;re online; offline, the app has to trust your input and tries to submit for real when it reaches the server.</p><h2 id="sync-errors" tabindex="-1">Sync errors <a class="header-anchor" href="#sync-errors" aria-label="Permalink to &quot;Sync errors&quot;">​</a></h2><p>If an item errors on upload (most often a temporary server issue), it goes to the <strong>Sync Errors</strong> section, accessed from:</p><p><strong>More → Sync Errors</strong></p><p>You&#39;ll see:</p><ul><li>The item that failed (e.g. &quot;checkin&quot;)</li><li>The error message</li><li>A <strong>Retry</strong> button</li><li>A <strong>Delete</strong> option (type DELETE to confirm)</li></ul><p><strong>Almost always the fix is to tap Retry.</strong> Most errors are transient — weak signal during upload, server just restarted, etc. A retry usually succeeds.</p><p>If the same item keeps failing after multiple retries, screenshot the error and send it to HR / IT.</p><h2 id="photos-and-offline" tabindex="-1">Photos and offline <a class="header-anchor" href="#photos-and-offline" aria-label="Permalink to &quot;Photos and offline&quot;">​</a></h2><p>Selfies and expense receipt photos are saved <strong>on-device</strong> (in the app&#39;s private storage) until they can be uploaded.</p><ul><li>Up to about 500 MB of photo storage — plenty for weeks of offline work</li><li>Photos are deleted from local storage <strong>only after</strong> they&#39;ve been successfully uploaded AND the check-in / claim has been accepted</li><li>Uninstalling the app clears all local photos — make sure you&#39;ve synced before uninstalling</li></ul><h2 id="background-sync-native-apk-only" tabindex="-1">Background sync (native APK only) <a class="header-anchor" href="#background-sync-native-apk-only" aria-label="Permalink to &quot;Background sync (native APK only)&quot;">​</a></h2><p>On the native Android app, the sync runs <strong>even when the app is closed</strong>. If your phone regains signal while Fateh HR is in the background or swiped away, queued items will upload automatically. You don&#39;t need to open the app.</p><p>The web app can&#39;t do this — browsers close their network connections when you close the tab.</p><h2 id="working-locally-safety-rules" tabindex="-1">&quot;Working locally&quot; safety rules <a class="header-anchor" href="#working-locally-safety-rules" aria-label="Permalink to &quot;&quot;Working locally&quot; safety rules&quot;">​</a></h2><ol><li><strong>Don&#39;t uninstall the app before syncing.</strong> All your queued items live inside the app. Uninstall = lost.</li><li><strong>Keep location on.</strong> Offline check-ins still need GPS to know where you are.</li><li><strong>Keep enough storage.</strong> The app needs a few hundred MB for queued photos.</li><li><strong>Open the app at least once a day.</strong> This lets it try to sync in the background, and keeps your session active.</li></ol><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/check-in">Check-in &amp; check-out</a></li><li><a href="/guide/leave">Apply for leave</a></li><li><a href="/guide/troubleshooting">Troubleshooting</a></li></ul>',34)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
